scwin.f_check = async function () {
  // 필수 조회조건 입력 여부(등록년도) Check
  if (!(await $c.gus.cfValidate($p, [ed_regYy], null, true))) {
    return false;
  }
  if (!(await $c.gus.cfValidate($p, [gr_saleCreditInfo], null, true))) {
    return false;
  }
  var checkIdx = gr_saleCreditInfo.getCheckedIndex("num");
  for (i = 0; i < checkIdx.length; i++) {
    //계약시작일자가 더 클경우 체크
    if (!(await $c.gus.cfIsAfterDate($p, ds_saleCreditInfo.getCellData(checkIdx[i], "stCtrtDt"), ds_saleCreditInfo.getCellData(checkIdx[i], "endCtrtDt")))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
      return false;
    }

    // 보증금액 0보다 큰값
    if (ds_saleCreditInfo.getCellData(checkIdx[i], "deposit") <= 0) {
      await $c.win.alert($p, "보증금액은 0 으로 입력할수 없습니다.");
      return false;
    }
  }
};
